// We steal the following routine from \MF.
func (prg *prg) printScaled(s int32) {
	// prints a scaled number, rounded to five digits
	var (
		delta int32 // amount of allowable inaccuracy
	)
	if s < 0 {
		prg.stdout.Write("-")
		s = -s // print the sign, if negative
	}
	prg.stdout.Write(s/0200000, knuth.WriteWidth(1)) // print the integer part
	s = 10*(s%0200000) + 5
	if s != 5 {
		delta = 10
		prg.stdout.Write(".")
		for {
			if delta > 0200000 {
				s = s + 0100000 - delta/2
			} // round the final digit
			prg.stdout.Write(string(rune(char(int32('0') + s/0200000))))
			s = 10 * (s % 0200000)
			delta = delta * 10
			if s <= delta {
				break
			}
		}
	}
}

